def execute(params):
    """Create a ZIP archive."""
    import zipfile
    import os

    zip_path = params.get('zipPath')
    source_paths = params.get('sourcePaths', [])

    if not zip_path:
        return {'success': False, 'error': 'zipPath parameter is required'}

    if not source_paths:
        return {'success': False, 'error': 'sourcePaths parameter is required'}

    try:
        with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as zip_ref:
            file_count = 0
            for source_path in source_paths:
                if os.path.isfile(source_path):
                    zip_ref.write(source_path, os.path.basename(source_path))
                    file_count += 1
                elif os.path.isdir(source_path):
                    for root, dirs, files in os.walk(source_path):
                        for file in files:
                            file_path = os.path.join(root, file)
                            arcname = os.path.relpath(file_path, os.path.dirname(source_path))
                            zip_ref.write(file_path, arcname)
                            file_count += 1

        return {
            'success': True,
            'message': f'Created ZIP with {file_count} files',
            'zipPath': zip_path,
            'fileCount': file_count
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

