        email_ids = messages[0].split()
        email_ids = email_ids[-limit:] if len(email_ids) > limit else email_ids

        emails = []
        for email_id in email_ids:
            status, msg_data = mail.fetch(email_id, '(RFC822)')
            msg = email.message_from_bytes(msg_data[0][1])

            subject = decode_header(msg['Subject'])[0][0]
            if isinstance(subject, bytes):
                subject = subject.decode()

            from_addr = msg.get('From')
            date = msg.get('Date')

            body = ''
            if msg.is_multipart():
                for part in msg.walk():
                    if part.get_content_type() == 'text/plain':
                        body = part.get_payload(decode=True).decode()
                        break
            else:
                body = msg.get_payload(decode=True).decode()

            attachments = []
            if msg.is_multipart():
                for part in msg.walk():
                    if part.get_content_disposition() == 'attachment':
                        filename = part.get_filename()
                        if filename:
                            attachments.append({
                                'filename': filename,
                                'content_type': part.get_content_type(),
                                'size': len(part.get_payload(decode=True))
                            })

            emails.append({
                'id': email_id.decode(),
                'subject': subject,
                'from': from_addr,
                'date': date,
                'body': body[:500] + '...' if len(body) > 500 else body,
                'attachments': attachments
            })

        mail.close()
        mail.logout()

        return {
            'success': True,
            'count': len(emails),
            'emails': emails
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Get file metadata."""
    import os
    import stat
    import datetime

    file_path = params.get('filePath')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    try:
        stats = os.stat(file_path)

        return {
            'success': True,
            'path': file_path,
            'size': stats.st_size,
            'created': datetime.datetime.fromtimestamp(stats.st_ctime).isoformat(),
            'modified': datetime.datetime.fromtimestamp(stats.st_mtime).isoformat(),
            'accessed': datetime.datetime.fromtimestamp(stats.st_atime).isoformat(),
            'permissions': oct(stat.S_IMODE(stats.st_mode)),
            'is_file': os.path.isfile(file_path),
            'is_directory': os.path.isdir(file_path)
        }
    except FileNotFoundError:
        return {'success': False, 'error': f'File not found: {file_path}'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Search for files by name pattern."""
    import os
    import fnmatch

    directory = params.get('directory')
    pattern = params.get('pattern')

    if not directory or not pattern:
        return {'success': False, 'error': 'directory and pattern parameters are required'}

    recursive = params.get('recursive', True)

    try:
        matches = []

        if recursive:
            for root, dirs, files in os.walk(directory):
                for filename in fnmatch.filter(files, pattern):
                    matches.append(os.path.join(root, filename))
        else:
            files = os.listdir(directory)
            for filename in fnmatch.filter(files, pattern):
                full_path = os.path.join(directory, filename)
                if os.path.isfile(full_path):
                    matches.append(full_path)

        return {
            'success': True,
            'count': len(matches),
            'files': matches
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Download a file from a URL."""
    import urllib.request
    import os

    url = params.get('url')
    save_path = params.get('savePath')

    if not url:
        return {'success': False, 'error': 'url parameter is required'}

    if not save_path:
        save_path = os.path.basename(url)

    try:
        urllib.request.urlretrieve(url, save_path)
        file_size = os.path.getsize(save_path)

        return {
            'success': True,
            'message': f'Downloaded {file_size} bytes',
            'savePath': save_path,
            'size': file_size
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Take a screenshot."""
    save_path = params.get('savePath', 'screenshot.png')

    try:
        import mss

        with mss.mss() as sct:
            monitor = sct.monitors[1]
            screenshot = sct.grab(monitor)
            mss.tools.to_png(screenshot.rgb, screenshot.size, output=save_path)

        return {
            'success': True,
            'message': f'Screenshot saved to {save_path}',
            'savePath': save_path
        }
    except ImportError:
        return {'success': False, 'error': 'mss module not installed. Install with: pip install mss'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Convert image format."""
    input_path = params.get('inputPath')
    output_path = params.get('outputPath')

    if not input_path or not output_path:
        return {'success': False, 'error': 'inputPath and outputPath parameters are required'}

    format_param = params.get('format', '').upper()

    try:
        from PIL import Image

        img = Image.open(input_path)

        if format_param:
            img.save(output_path, format=format_param)
        else:
            img.save(output_path)

        return {
            'success': True,
            'message': f'Image converted: {input_path} -> {output_path}',
            'inputPath': input_path,
            'outputPath': output_path,
            'format': format_param if format_param else 'auto'
        }
    except ImportError:
        return {'success': False, 'error': 'PIL (Pillow) not installed. Install with: pip install pillow'}
    except Exception as e:
        return {'success': False, 'error': str(e)}
